import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Students = () => {
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();
  const role = localStorage.getItem('role');

  useEffect(() => {
    fetch('http://127.0.0.1:8000/api/student/')
      .then((res) => res.json())
      .then((data) => {
        // Make sure it's an array
        if (Array.isArray(data)) {
          setStudents(data);
        } else if (data.results) {
          setStudents(data.results); // for paginated responses
        } else {
          setStudents([]); // fallback
        }
        setLoading(false);
      })
      .catch((error) => {
        console.error('Error fetching students:', error);
        setStudents([]);
        setLoading(false);
      });
  }, []);

  return (
    <div className="container py-5">
      {role === 'teacher' ? (
  <button className="btn btn-secondary mb-3" onClick={() => navigate('/teacher-dashboard')}>
    ← Back to Dashboard
  </button>
) : role === 'student' ? (
  <button className="btn btn-secondary mb-3" onClick={() => navigate('/student-dashboard')}>
    ← Back to Dashboard
  </button>
) : null}
      <h2 className="mb-4">📚 Students</h2>

      {loading ? (
        <p>Loading student data...</p>
      ) : students.length === 0 ? (
        <p>No students found.</p>
      ) : (
        <table className="table table-striped">
          <thead>
            <tr>
              <th>Username</th>
              <th>Email</th>
              <th>Student ID</th>
              <th>Age</th>
            </tr>
          </thead>
          <tbody>
            {students.map((student) => (
              <tr key={student.id}>
                <td>{student.user?.username}</td>
                <td>{student.email}</td>
                <td>{student.student_id}</td>
                <td>{student.age}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default Students;
